import { createGlobalStyle } from "styled-components";

export const GlobalStyles = createGlobalStyle`
  html {
    /* Pegasus Grayscale */
    --gs-title-active: #14142B;
    --gs-body: #4E4B66;
    --gs-label: #6E7191;
    --gs-placeholder: #A0A3BD;
    --gs-line: #D9DBE9;
    --gs-input-bg: #EFF0F7;
    --gs-bg: #F7F7FC;
    --gs-offwhite: #FCFCFC;
    /* Pegasus Colors */
    --pegasus-primary: #5F2EEA;
    --pegasus-primary-dark: #2A00A2;;
    --pegasus-primary-darkmode: #BCA4FF;;
    --pegasus-secondary: #1CC8EE;
    --pegasus-secondary-dark: #0096B7;
    --pegasus-secondary-darkmode: #82E9FF;
    --pegasus-error: #ED2E7E;
    --pegasus-error-dark: #C30052;
    --pegasus-error-darkmode: #FF84B7;
    --pegasus-success: #00BA88;
    --pegasus-success-dark: #00966D;
    --pegasus-success-darkmode: #34EAB9;
    --pegasus-warning: #F4B740;
    --pegasus-warning-dark: #946200;
    --pegasus-warning-darkmode: #FFD789;
    --pegasus-gradient-primary: linear-gradient(114.44deg, #7433FF 0%, #FFA3FD 100%);
    --pegasus-gradient-secondary: linear-gradient(114.44deg, #624AF2 0%, #50DDC3 100%);
    --pegasus-gradient-accent: linear-gradient(114.44deg, #EB0055 0%, #FFFA80 100%);
  }


  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }
  body {
    font-family: "Rubik", sans-serif;
    background: ${(props: any) => props.theme.colors.primary};
  }
  a, button, input, textarea {
    font-family: inherit;
    &:focus:not(:focus-visible) {
      outline: 0;
    }
    &:focus-visible,
    &:-moz-focusring {
      outline: 1px solid ${(props: any) => props.theme.colors.accent}
    }
  }
`;
